# g_spin <tick> ‚ÄĒ emit one braille spinner frame for the given tick counter.
# Uses awk substr (UTF-8 aware under gawk) so multibyte braille is safe.
g_spin() {
    awk -v s="$G_SPINNER" -v i="${1:-0}" 'BEGIN { n = length(s); printf "%s", substr(s, (i % n) + 1, 1) }'
}
